use std::collections::VecDeque;

struct StateManager {
    cleanup_hooks: VecDeque<Box<dyn Fn() + Send>>
}

impl StateManager {
    fn new() -> Self {
        StateManager { cleanup_hooks: VecDeque::new() }
    }

    fn register_hook<F>(&mut self, hook: F) where F: Fn() + 'static + Send {
        self.cleanup_hooks.push_back(Box::new(hook));
    }

    async fn shutdown(&mut self) {
        println!("Initiating graceful shutdown sequence...");
        while let Some(hook) = self.cleanup_hooks.pop_front() {
            println!("Executing cleanup routine...");
            hook();
        }
        println!("All hooks executed. State successfully persisted.");
    }
}

#[tokio::main]
async fn main() {
    let mut manager = StateManager::new();

    manager.register_hook(|| {
        println!("[Hook 1]: Releasing network resources and flushing cache.");
    });

    manager.register_hook(|| {
        println!("[Hook 2]: Validating local service credentials against vault snapshot.");
    });

    manager.register_hook(|| {
        println!("[Hook 3]: Running final state reconciliation job.");
    });

    manager.shutdown().await;
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

type Handler = Box<dyn Fn(String) -> String + Send + Sync>;

struct PluginRegistry {
    handlers: Arc<Mutex<HashMap<String, Handler>>>,
}

impl PluginRegistry {
    fn new() -> Self {
        PluginRegistry { 
            handlers: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    fn register_handler(&self, key: impl Into<String>, handler: impl Fn(String) -> String + 'static + Send + Sync) {
        let mut handlers = self.handlers.lock().unwrap();
        handlers.insert(key.into(), Box::new(move |input| { 
            handler(input)
        }));
    }

    fn execute_handler(&self, key: &str, data: String) -> Result<String, &'static str> {
        let handlers = self.handlers.lock().unwrap();
        match handlers.get(key) {
            Some(handler) => Ok(handler(data)),
            None => Err("No handler registered for this key"),
        }
    }
}

fn main() {
    let registry = PluginRegistry::new();

    registry.register_handler("user_lookup", |input| format!("Executed DB query for user: {}", input));
    registry.register_handler("process_payment", |input| format!("Processing transaction with ID: {}", input));

    let result1 = registry.execute_handler("user_lookup", "auth_token_xyz".to_string());
    println!("Result 1: {:?}", result1);

    let result2 = registry.execute_handler("process_payment", "txn_987".to_string());
    println!("Result 2: {:?}", result2);

    let result3 = registry.execute_handler("unknown_action", "data".to_string());
    println!("Result 3: {:?}", result3);
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, prelude::*};

struct PhotoBatchRenamer {
    metadata: HashMap<String, String>,
}

impl PhotoBatchRenamer {
    fn new() -> Self {
        PhotoBatchRenamer {
            metadata: HashMap::new(),
        }
    }

    fn load_metadata(&mut self, file_path: &str) -> io::Result<()> {
        let mut file = File::open(file_path)?;
        let mut contents = String::new();
        file.read_to_string(&mut contents)?; 

        for line in contents.lines() {
            if !line.contains("backup") {
                let parts: Vec<&str> = line.split(": ").collect();
                if parts.len() == 2 {
                    self.metadata.insert(parts[0].to_string(), parts[1].to_string());
                }
            }
        }
        Ok(())
    }

    fn process_renames(&self) -> HashMap<String, String> {
        let mut renames = HashMap::new();
        for (original, date) in &self.metadata {
            let new_name = format!("photo_{}_{}.jpg", date, original);
            renames.insert(original.clone(), new_name);
        }
        renames
    }
}

fn main() -> io::Result<()> {
    let mut renamer = PhotoBatchRenamer::new();
    renamer.load_metadata("file_list.txt")?;

    println!("Found {} files to process.", renamer.metadata.len());

    let renames = renamer.process_renames();

    for (original, new) in renames { 
        println!("Renaming '{}' to '{}'", original, new);
    }

    Ok(())
}

use std::collections::HashMap;

struct EventHandler {
    callbacks: HashMap<String, Vec<Box<dyn Fn(u32) + Send>>>,
}

impl EventHandler {
    fn new() -> Self {
        EventHandler { 
            callbacks: HashMap::new()
        }
    }

    fn register_callback<F>(&mut self, event_name: &str, callback: F) 
    where
        F: Fn(u32) + 'static + Send
    {
        self.callbacks.entry(event_name.to_string()).or_default().push(Box::new(callback));
    }

    fn trigger_event(&self, event_name: &str, data: u32) {
        if let Some(callbacks) = self.callbacks.get(event_name) {
            for callback in callbacks.iter() {
                callback(data);
            }
        }
    }
}

fn main() {
    let mut handler = EventHandler::new();

    handler.register_callback("temperature", |value| { 
        println!("Callback executed for temperature with value: {}", value);
    });

    handler.register_callback("humidity", |value| { 
        println!("Callback executed for humidity with value: {}", value);
    });

    let event = "temperature";
    let sensor_data = 42;
    handler.trigger_event(event, sensor_data);

    let event2 = "humidity";
    let sensor_data2 = 99;
    handler.trigger_event(event2, sensor_data2);
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

type Callback = Box<dyn Fn(f64) + Send + Sync>;

struct SystemMonitor {
    callbacks: Arc<Mutex<HashMap<&'static str, Vec<Callback>>>>,
}

impl SystemMonitor {
    fn new() -> Self {
        SystemMonitor {
            callbacks: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    fn register_callback<T: 'static + Fn(f64) + Send + Sync + Clone>( 
        &self, 
        event_type: &'static str,
        callback: T
    ) -> Result<(), &'static str> {
        let mut callbacks = self.callbacks.lock().unwrap();
        let event_vec = callbacks.entry(event_type).or_insert_with(Vec::new);
        event_vec.push(Box::new(move |val| { 
            let _ = callback(val); 
        }));
        Ok(())
    }

    fn simulate_update(&self, event_type: &'static str, value: f64) {
        let callbacks = self.callbacks.lock().unwrap();
        if let Some(event_vec) = callbacks.get(event_type) {
            for callback in event_vec.iter() {
                callback(value);
            }
        }
    }
}

fn main() {
    let monitor = SystemMonitor::new();

    monitor.register_callback("cpu_change", |val| { 
        println!("CPU Alert: Value changed to {:.2}", val);
    }).unwrap();

    monitor.register_callback("memory_low", |val| { 
        println!("Memory Warning: Low usage detected at {:.1} percent.", val);
    }).unwrap();

    println!("Starting simulation...");
    monitor.simulate_update("cpu_change", 0.45); 
    monitor.simulate_update("memory_low", 22.7);
    monitor.simulate_update("cpu_change", 0.61);
}
